    if (indexHtml) {
      return reply.type('text/html').send(indexHtml)
    }
    return {
      message: 'Fastify Backend',
      docs: config.NODE_ENV !== 'production' ? '/docs' : 'disabled in production',
      health: '/health'
    }
  })

